      }
    "))
  ),

  titlePanel("Truth Table Builder"),

  sidebarLayout(
    sidebarPanel(
      textInput("vars", "Variables:", "p q"),
      textInput("expr", "Expression:", ""),

      h4("Variables"),
      uiOutput("var_buttons"),

      h4("Connectives"),
      div(
        actionButton("not", "¬"),
        actionButton("and", "∧"),
        actionButton("or", "∨"),
        actionButton("imp", "→"),
        actionButton("iff", "↔")
      ),

      h4("Brackets"),
      div(
        actionButton("lpar", "("),
        actionButton("rpar", ")")
